import { useMemo, useEffect, useState } from "react";
import { Link, useSearchParams } from "react-router-dom";
import { motion } from "framer-motion";
import {
  Clock, ArrowUpRight, TrendingUp, TrendingDown, Minus, Star,
  Search, Filter, X, ChevronDown, ChevronUp,
} from "lucide-react";
import Header from "@/components/landing/Header";
import Footer from "@/components/landing/Footer";
import { useMarket, useRecentlyViewed, pushRecentlyViewed } from "@/lib/MarketContext";
import { fmt, fmtTime } from "@/lib/parseItem";
import { Skeleton } from "@/components/ui/skeleton";
import { openItem } from "@/components/landing/DetailDrawer";
import { Reveal } from "@/components/landing/motion";
import BackToTop from "@/components/landing/BackToTop";

const HISTORY_KEY = "castia.tradingHistory";
const HISTORY_MAX = 50;

function writeTradingHistory(history) {
  try {
    localStorage.setItem(HISTORY_KEY, JSON.stringify(history.slice(-HISTORY_MAX)));
    window.dispatchEvent(new CustomEvent("castia:history"));
  } catch { /* ignore */ }
}

export function recordTrade(itemKey) {
  if (!itemKey) return;
  try {
    const raw = localStorage.getItem(HISTORY_KEY);
    const history = raw ? JSON.parse(raw) : [];
    const ts = Date.now();
    const entry = { key: itemKey, ts };
    const filtered = history.filter(h => h.key !== itemKey);
    writeTradingHistory([{ ts, ...entry }, ...filtered]);
    pushRecentlyViewed(itemKey);
  } catch { /* ignore */ }
}

export function RecordTradeButton({ itemKey, children }) {
  return (
    <button
      onClick={() => { recordTrade(itemKey); openItem(null, null, itemKey); }}
      className={children ? undefined : "inline-flex items-center gap-2 border border-white/10 hover:border-emerald-500/40 text-zinc-300 hover:text-emerald-400 font-bold uppercase tracking-[0.18em] text-[10px] px-4 py-2.5 rounded-sm transition-colors"}
    >
      {children || <>View details <ArrowUpRight className="w-3.5 h-3.5" /></>}
    </button>
  );
}

const TrendIcon = ({ trend }) => {
  if (trend === "up" || trend === "rising") return <TrendingUp className="w-4 h-4 text-emerald-400" />;
  if (trend === "down" || trend === "falling") return <TrendingDown className="w-4 h-4 text-red-400" />;
  return <Minus className="w-4 h-4 text-zinc-500" />;
};

function SkeletonTable() {
  return (
    <div className="border border-white/10 rounded-2xl overflow-hidden">
      <div className="bg-white/[0.02] border-b border-white/10 px-4 py-3 flex gap-4">
        {Array.from({ length: 5 }).map((_, i) => (
          <Skeleton key={i} className="h-3 flex-1" />
        ))}
      </div>
      {Array.from({ length: 8 }).map((_, r) => (
        <div key={r} className="border-b border-white/5 px-4 py-4 flex gap-4">
          {Array.from({ length: 5 }).map((_, c) => (
            <Skeleton key={c} className="h-4 flex-1" style={{ width: c === 0 ? "40%" : undefined }} />
          ))}
        </div>
      ))}
    </div>
  );
}

export default function TradingHistoryPage() {
  const { market } = useMarket();
  const recentlyViewed = useRecentlyViewed();
  const [searchParams, setSearchParams] = useSearchParams();
  const [tradingHistory, setTradingHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filterQ, setFilterQ] = useState("");
  const [sortKey, setSortKey] = useState("ts");
  const [sortDir, setSortDir] = useState("desc");

  useEffect(() => {
    const load = () => {
      try {
        const raw = localStorage.getItem(HISTORY_KEY);
        setTradingHistory(raw ? JSON.parse(raw) : []);
      } catch { setTradingHistory([]); }
      setLoading(false);
    };
    load();
    window.addEventListener("castia:history", load);
    return () => window.removeEventListener("castia:history", load);
  }, []);

  const items = useMemo(() => {
    const historyItems = tradingHistory.length > 0 ? tradingHistory : recentlyViewed.map(k => ({ key: k, ts: Date.now() }));
    return historyItems
      .map((entry) => {
        const key = typeof entry === "string" ? entry : entry.key;
        const ts = typeof entry === "string" ? Date.now() : entry.ts;
        return { key, ts, row: market?.rowsByKey?.get(key) };
      })
      .filter(({ row }) => row);
  }, [tradingHistory, recentlyViewed, market]);

  const filtered = useMemo(() => {
    if (!filterQ) return items;
    const q = filterQ.toLowerCase();
    return items.filter((i) => i.row.name?.toLowerCase().includes(q) || i.row.category?.toLowerCase().includes(q));
  }, [items, filterQ]);

  const sorted = useMemo(() => {
    const arr = [...filtered];
    if (sortKey === "name") {
      arr.sort((a, b) => sortDir === "asc" ? a.row.name.localeCompare(b.row.name) : b.row.name.localeCompare(a.row.name));
    } else if (sortKey === "median") {
      arr.sort((a, b) => sortDir === "asc" ? (a.row.median || 0) - (b.row.median || 0) : (b.row.median || 0) - (a.row.median || 0));
    } else {
      arr.sort((a, b) => sortDir === "asc" ? (a.ts || 0) - (b.ts || 0) : (b.ts || 0) - (a.ts || 0));
    }
    return arr;
  }, [filtered, sortKey, sortDir]);

  const totalValue = useMemo(() => sorted.reduce((s, i) => s + (i.row.median || 0), 0), [sorted]);

  const toggleSort = (key) => {
    if (sortKey === key) {
      setSortDir((d) => d === "asc" ? "desc" : "asc");
    } else {
      setSortKey(key);
      setSortDir(key === "ts" ? "desc" : "asc");
    }
  };

  const handleOpen = (key) => {
    recordTrade(key);
    openItem(searchParams, setSearchParams, key);
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-bg-base text-white font-body">
        <Header />
        <main className="pt-32 pb-24">
          <div className="max-w-7xl mx-auto px-6 md:px-12 lg:px-16">
            <Skeleton className="h-4 w-32 mb-4" />
            <Skeleton className="h-12 w-96 mb-8" />
            <div className="grid grid-cols-2 md:grid-cols-4 gap-px bg-white/10 border border-white/10 rounded-lg overflow-hidden mb-8">
              {Array.from({ length: 4 }).map((_, i) => (
                <div key={i} className="bg-bg-base/80 px-6 py-5 space-y-2">
                  <Skeleton className="h-3 w-16" />
                  <Skeleton className="h-7 w-20" />
                </div>
              ))}
            </div>
            <SkeletonTable />
          </div>
        </main>
        <Footer />
      </div>
    );
  }

  return (
    <div data-testid="trading-history-page" className="min-h-screen bg-bg-base text-white font-body">
      <Header />
      <main className="pt-32 pb-24">
        <div className="max-w-7xl mx-auto px-6 md:px-12 lg:px-16">
          <Reveal>
            <div className="font-mono text-[11px] uppercase tracking-[0.25em] text-emerald-400 mb-4 inline-flex items-center gap-2">
              <Clock className="w-3 h-3" /> / Recently Viewed
            </div>
            <h1 className="font-heading text-5xl lg:text-7xl tracking-tighter font-black leading-[0.95] mb-8">
              Your <span className="text-emerald-400">Trading History</span>
            </h1>
            <p className="text-zinc-400 max-w-2xl text-lg">
              Items you've examined or tracked. This is a local history — no data is sent anywhere.
            </p>
          </Reveal>

          {sorted.length === 0 ? (
            <Reveal>
              <div data-testid="trading-history-empty" className="mt-16 text-center max-w-md mx-auto">
                <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-emerald-500/10 border border-emerald-500/30 mb-6">
                  <Clock className="w-7 h-7 text-emerald-400" />
                </div>
                <h2 className="font-heading text-2xl font-black mb-3">No recently viewed items</h2>
                <p className="text-zinc-400 text-sm leading-relaxed mb-6">
                  Browse listings and examine items to build your viewing history.
                </p>
                <Link
                  to="/listings"
                  data-testid="trading-history-browse"
                  className="inline-flex items-center gap-2 bg-emerald-500 hover:bg-emerald-400 text-black font-bold uppercase tracking-[0.18em] text-xs px-5 py-3 rounded-sm transition-colors"
                >
                  Browse listings <ArrowUpRight className="w-4 h-4" />
                </Link>
              </div>
            </Reveal>
          ) : (
            <>
              {/* Summary bar */}
              <Reveal>
                <div className="mt-6 grid grid-cols-2 md:grid-cols-4 gap-px bg-white/10 border border-white/10 rounded-lg overflow-hidden">
                  {[
                    { l: "Total items", v: sorted.length },
                    { l: "Est. value", v: totalValue > 0 ? fmt(totalValue) : "—" },
                    { l: "Last viewed", v: fmtTime(sorted[0]?.ts || 0) },
                    { l: "Active alerts", v: "—" },
                  ].map((s) => (
                    <div key={s.l} className="bg-bg-base/80 px-6 py-5">
                      <div className="font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500">{s.l}</div>
                      <div className="mt-1 font-heading text-2xl font-black tabular text-white">{s.v}</div>
                    </div>
                  ))}
                </div>
              </Reveal>

              {/* Toolbar */}
              <Reveal delay={0.05}>
                <div className="flex items-center gap-3 mt-8 mb-4 flex-wrap">
                  <div className="relative flex-1 min-w-[160px] max-w-xs">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-zinc-500 pointer-events-none" />
                    <input
                      value={filterQ}
                      onChange={(e) => setFilterQ(e.target.value)}
                      placeholder="Filter by item or category…"
                      className="w-full bg-white/[0.04] border border-white/10 rounded-sm pl-9 pr-3 py-2 text-xs text-white placeholder:text-zinc-600 focus:outline-none focus:border-emerald-500/50 transition-colors"
                    />
                    {filterQ && (
                      <button onClick={() => setFilterQ("")} className="absolute right-2 top-1/2 -translate-y-1/2 text-zinc-500 hover:text-white">
                        <X className="w-3 h-3" />
                      </button>
                    )}
                  </div>
                  <div className="flex items-center gap-1 text-[10px] text-zinc-500 font-mono">
                    <Filter className="w-3 h-3" />
                    {filtered.length} of {items.length}
                  </div>
                </div>
              </Reveal>

              {/* Desktop: Table */}
              <div className="hidden md:block">
                <Reveal delay={0.1}>
                  <div className="border border-white/10 rounded-2xl overflow-x-auto">
                    <table className="w-full text-sm">
                      <thead>
                        <tr className="bg-white/[0.02] border-b border-white/10 text-left">
                          <th className="px-4 py-3 w-12"></th>
                          <th className="px-4 py-3 font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500">
                            <button onClick={() => toggleSort("name")} className="inline-flex items-center gap-1 hover:text-white transition-colors">
                              Item {sortKey === "name" && (sortDir === "asc" ? <ChevronUp className="w-3 h-3" /> : <ChevronDown className="w-3 h-3" />)}
                            </button>
                          </th>
                          <th className="px-4 py-3 font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500 hidden sm:table-cell">Category</th>
                          <th className="px-4 py-3 font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500 text-right">
                            <button onClick={() => toggleSort("median")} className="inline-flex items-center gap-1 hover:text-white transition-colors">
                              Median {sortKey === "median" && (sortDir === "asc" ? <ChevronUp className="w-3 h-3" /> : <ChevronDown className="w-3 h-3" />)}
                            </button>
                          </th>
                          <th className="px-4 py-3 font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500 hidden md:table-cell">Trend</th>
                          <th className="px-4 py-3 font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500 text-right">
                            <button onClick={() => toggleSort("ts")} className="inline-flex items-center gap-1 hover:text-white transition-colors">
                              Last seen {sortKey === "ts" && (sortDir === "asc" ? <ChevronUp className="w-3 h-3" /> : <ChevronDown className="w-3 h-3" />)}
                            </button>
                          </th>
                        </tr>
                      </thead>
                      <tbody>
                        {sorted.map((i, idx) => {
                          const { key, row } = i;
                          const isLatest = idx === 0;
                          return (
                            <tr
                              key={key}
                              data-testid={`history-row-${idx}`}
                              onClick={() => handleOpen(key)}
                              tabIndex={0}
                              role="link"
                              className="border-b border-white/5 last:border-0 hover:bg-white/[0.03] transition-colors cursor-pointer group"
                            >
                              <td className="px-4 py-4">
                                <Star className={`w-4 h-4 transition-colors ${isLatest ? "text-amber-400" : "text-zinc-600 group-hover:text-amber-400"}`} />
                              </td>
                              <td className="px-4 py-4">
                                <div className="font-heading font-bold text-white group-hover:text-emerald-400 transition-colors">{row.name}</div>
                              </td>
                              <td className="px-4 py-4 hidden sm:table-cell">
                                <span className="font-mono text-[10px] uppercase tracking-wider text-zinc-500">{row.category}</span>
                              </td>
                              <td className="px-4 py-4 text-right">
                                <span className="font-mono tabular text-white font-bold">{fmt(row.median)}</span>
                              </td>
                              <td className="px-4 py-4 hidden md:table-cell">
                                <div className="inline-flex items-center gap-1.5">
                                  <TrendIcon trend={row.trend} />
                                  <span className="font-mono text-[10px] uppercase tracking-wider text-zinc-500">{row.trend}</span>
                                </div>
                              </td>
                              <td className="px-4 py-4 text-right">
                                <span className="font-mono text-[10px] text-zinc-500" title={new Date(i.ts).toLocaleString()}>{fmtTime(i.ts)}</span>
                              </td>
                            </tr>
                          );
                        })}
                      </tbody>
                    </table>
                  </div>
                </Reveal>
              </div>

              {/* Mobile: Card list */}
              <div className="md:hidden">
                <Reveal delay={0.1}>
                  <div className="space-y-3">
                    {sorted.map((i, idx) => {
                      const { key, row } = i;
                      return (
                        <motion.div
                          key={key}
                          initial={{ opacity: 0, y: 8 }}
                          animate={{ opacity: 1, y: 0 }}
                          transition={{ delay: idx * 0.02 }}
                          onClick={() => handleOpen(key)}
                          className="bg-white/[0.02] border border-white/10 rounded-xl p-4 cursor-pointer active:bg-white/[0.04] transition-colors"
                        >
                          <div className="flex items-start justify-between mb-2">
                            <div className="font-heading font-bold text-white">{row.name}</div>
                            <ArrowUpRight className="w-4 h-4 text-zinc-500 shrink-0" />
                          </div>
                          <div className="flex items-center gap-2 text-[10px] text-zinc-500 font-mono uppercase tracking-wider mb-3">
                            <span>{row.category}</span>
                            {row.trend && (
                              <>
                                <span className="text-zinc-600">·</span>
                                <span className="flex items-center gap-1">
                                  <TrendIcon trend={row.trend} /> {row.trend}
                                </span>
                              </>
                            )}
                          </div>
                          <div className="flex items-center justify-between">
                            <span className="font-mono tabular text-emerald-400 font-bold">{fmt(row.median)}</span>
                            <span className="font-mono text-[10px] text-zinc-500">{fmtTime(i.ts)}</span>
                          </div>
                        </motion.div>
                      );
                    })}
                  </div>
                </Reveal>
              </div>
            </>
          )}
        </div>
      </main>
      <Footer />
      <BackToTop />
    </div>
  );
}
